/**
 * 学习进度持久化（localStorage）
 * 仅在客户端使用，SSR 环境下不会调用
 */

const STORAGE_KEY = "math-haohao-wan-progress";

export type ProgressMap = Record<string, string[]>; // topicId -> stepId[]

/** 从 localStorage 读取进度 */
export function loadProgress(): ProgressMap {
  if (typeof window === "undefined") return {};
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : {};
  } catch {
    return {};
  }
}

/** 标记某步完成 */
export function markStepDone(topicId: string, stepId: string): void {
  if (typeof window === "undefined") return;
  const progress = loadProgress();
  if (!progress[topicId]) progress[topicId] = [];
  if (!progress[topicId].includes(stepId)) {
    progress[topicId].push(stepId);
  }
  localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
}

/** 检查某步是否已完成 */
export function isStepDone(topicId: string, stepId: string): boolean {
  const progress = loadProgress();
  return progress[topicId]?.includes(stepId) ?? false;
}

/** 获取某知识点的已完成步骤数 */
export function getDoneCount(topicId: string): number {
  const progress = loadProgress();
  return progress[topicId]?.length ?? 0;
}
