"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { getTopic } from "@/content";
import BackButton from "@/components/BackButton";
import { isStepDone } from "@/lib/progress";

const STEP_BAR_COLORS: string[] = [
  "var(--accent)", "var(--primary)", "var(--accent2)", "var(--accent3)",
  "var(--accent)", "var(--primary)", "var(--accent2)",
];

export default function LearningPathPage() {
  const topic = getTopic("motion");
  const steps = topic?.steps ?? [];

  const [doneSteps, setDoneSteps] = useState<Set<string>>(new Set());
  useEffect(() => {
    const done = new Set<string>();
    steps.forEach(s => {
      if (isStepDone("motion", s.id)) done.add(s.id);
    });
    setDoneSteps(done);
  }, []);

  if (!topic) return null;

  return (
    <main className="relative mx-auto w-full max-w-3xl overflow-hidden px-6 py-8">
      <div className="pointer-events-none absolute -top-10 -right-10 h-40 w-40 rounded-full bg-[var(--primary-light)] opacity-15 blur-3xl" />
      <div className="pointer-events-none absolute bottom-20 -left-10 h-48 w-48 rounded-full bg-[var(--accent3-light)] opacity-15 blur-3xl" />
      <BackButton href="/" label="← 返回首页" />
      <div className="relative z-10 mt-6 text-center">
        <div className="text-5xl">{topic.icon}</div>
        <h1 className="mt-3 text-3xl font-extrabold text-[var(--text)]">{topic.title}</h1>
        <p className="mt-2 text-[var(--text-secondary)]">{topic.subtitle}</p>
      </div>
      <div className="relative z-10 mt-12">
        <div className="absolute left-[3.25rem] top-0 bottom-0 w-1 rounded-full" style={{ background: "linear-gradient(to bottom, var(--primary), var(--accent), var(--accent3), var(--accent2))", opacity: 0.3 }} />
        <div className="space-y-4">
          {steps.map((step, idx) => {
            const color = STEP_BAR_COLORS[idx] || "var(--primary)";
            return (
              <div key={step.id} className="relative flex items-start gap-4">
                <div className="relative z-10 flex h-16 w-16 shrink-0 items-center justify-center rounded-2xl text-2xl shadow-[var(--shadow-sm)]" style={{ backgroundColor: color, color: "white" }}>
                  {step.icon}
                </div>
                <Link href={step.path} className="flex-1 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)] transition-all duration-300 hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]">
                  <div className="flex items-center gap-2">
                    <span className="rounded-lg px-2 py-0.5 text-xs font-bold text-white" style={{ backgroundColor: color }}>
                      第 {idx + 1} 步
                    </span>
                    <span className="text-lg font-bold text-[var(--text)]">{step.label}</span>
                    {doneSteps.has(step.id) && (
                      <span className="text-sm text-[var(--signal-confirmed)] font-bold" title="已完成">&#10003;</span>
                    )}
                    <span className="rounded-full bg-[var(--bg-soft)] px-2.5 py-0.5 text-xs text-[var(--text-secondary)]">
                      {step.subtitle}
                    </span>
                  </div>
                  <p className="mt-1.5 text-sm text-[var(--text-secondary)]">{step.description}</p>
                </Link>
              </div>
            );
          })}
        </div>
      </div>
    </main>
  );
}
